import { searchByPhone, searchById } from "../api";

const handleSearch = async () => {
  let data = null;

  if (phone) {
    data = await searchByPhone(phone);
  } else if (id) {
    data = await searchById(id);
  }

  if (!data || data.detail) {
    alert("Not found");
    return;
  }

  setResult(data);
};
